import os
import io
import azure.functions as func
from azure.cosmosdb.databases import CosmosDatabase
from azure.cosmosdb.containers import Container
from azure.storage.blob import BlobServiceClient, BlobClient
from azure.eventgrid.events import EventGridEvent
import json

def main(myqueueitem: func.QueueItem) -> func.HttpResponse:
    if not myqueueitem.get_json():
        return func.HttpResponse(
             "Please pass a blob url in the Queue Item",
             status_code=400
        )

    blob_url = myqueueitem.get_json().get("blobUrl")
    cosmosdb_account = os.environ["AZURE_COSMOSDB_ACCOUNT"]
    cosmosdb_key = os.environ["AZURE_COSMOSDB_KEY"]
    eventgrid_topic = os.environ["EVENTGRID_TOPIC"]

    blob_service_client = BlobServiceClient.from_connection_string(os.environ["AZURE_STORAGE_CONNECTION_STRING"])
    blob_client = blob_service_client.get_blob_client(blob_url)
    download_stream = blob_client.download_blob().readall()

    data = json.loads(download_stream)

    cosmosdb_client = CosmosClient(cosmosdb_account, cosmosdb_key)
    db = CosmosDatabase(id="yourDatabaseId", client=cosmosdb_client)
    container = db.create_container_if_not_exists(id="yourContainerId")

    response = container.create_item(data, partition_key=str(data["partitionKey"]))

    event = EventGridEvent(raw_event=data)
    event.topic = eventgrid_topic

    event_grid_client = EventGridClient.from_connection_string(os.environ["AZURE_EVENTGRID_CONNECTION_STRING"])
    result = event_grid_client.send_event(event)

    return func.HttpResponse(f"Processed blob {blob_url}")